 54→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
 55→pub enum StopReason {
 56→    #[serde(rename = "end_turn")]
 57→    EndTurn,
 58→    #[serde(rename = "max_tokens")]
 59→    MaxTokens,
 60→    #[serde(rename = "tool_use")]
 61→    ToolUse,
 62→}
