 85→pub struct Message {
 86→    pub role: String,
 87→    pub content: Vec<ContentBlock>,
 88→}
 89→
 90→#[derive(Debug, Clone, Default, Serialize, Deserialize)]
 91→pub struct Usage {
 92→    pub input_tokens: u64,
 93→    pub output_tokens: u64,
 94→    pub cache_creation_input_tokens: u64,
 95→    pub cache_read_input_tokens: u64,
 96→}
